"""User storage and search functionality.

Provides in-memory user management with search capabilities.
The search index is built once at initialization from the initial
user list and is used for fast lookups.
"""
from typing import List, Optional
from models import User


class UserStore:
    """In-memory user store with search."""

    def __init__(self, users: List[User] = None):
        self._users = {}
        self._search_index = {}
        if users:
            for user in users:
                self._users[user.username] = user
            self._build_index()

    def add_user(self, user: User) -> None:
        """Add a user to the store.

        Note: This adds the user to the main store. The search index
        is built separately and is a snapshot of users at init time.
        """
        if user.username in self._users:
            raise ValueError(f"User {user.username!r} already exists")
        self._users[user.username] = user

    def remove_user(self, username: str) -> User:
        """Remove and return a user from the store."""
        if username not in self._users:
            raise KeyError(f"User {username!r} not found")
        user = self._users.pop(username)
        # Remove from index if present
        self._search_index.pop(username, None)
        return user

    def get_user(self, username: str) -> Optional[User]:
        """Get a user by exact username."""
        return self._users.get(username)

    def list_users(self) -> List[User]:
        """Return all users."""
        return list(self._users.values())

    def search_users(self, query: str) -> List[User]:
        """Search users by username, email, or full name.

        Performs partial string matching against the search index.
        Returns list of matching User objects.
        """
        # BUG 1: No handling of None/empty query — crashes with AttributeError
        # BUG 2: Case-sensitive matching — users expect case-insensitive
        results = []
        for entry_username, fields in self._search_index.items():
            for field_value in fields.values():
                if query in field_value:
                    if entry_username in self._users:
                        results.append(self._users[entry_username])
                    break
        return results

    def _build_index(self) -> None:
        """Build the search index from current users.

        The index maps username -> {field_name: field_value} for
        searchable fields.
        """
        self._search_index = {}
        for username, user in self._users.items():
            self._search_index[username] = {
                # BUG 3: Typo — 'usernme' instead of 'username'
                "usernme": user.username,
                "email": user.email,
                "full_name": user.full_name,
            }

    def count(self) -> int:
        """Return number of users in the store."""
        return len(self._users)

    def search_by_role(self, role: str) -> List[User]:
        """Return all users with the given role."""
        return [u for u in self._users.values() if u.role == role]

    def get_active_users(self) -> List[User]:
        """Return all active users."""
        return [u for u in self._users.values() if u.active]
